// Helpers - Pure utility functions (no side effects)

/**
 * Development-only logging. Logs to console.error in development, silent in production.
 * FIX-002: Changed from throwing to logging behavior.
 */
export function devLog(error: Error): void {
  if (process.env.NODE_ENV !== 'production') {
    console.error('[devLog]', error.message, error);
  }
}

/**
 * Development-only assertion. Throws in development, silent in production.
 * Use this when you want to throw errors during development.
 */
export function devAssert(error: Error): void {
  if (process.env.NODE_ENV !== 'production') {
    throw error;
  }
}

/**
 * Type-safe Object.entries with proper tuple types.
 * FIX-008: Recommended replacement for deprecated objectMap.
 */
export function objectEntries<T extends Record<string, unknown>>(
  obj: T
): Array<[keyof T & string, T[keyof T]]> {
  return Object.entries(obj) as Array<[keyof T & string, T[keyof T]]>;
}

/**
 * Type-safe Object.keys with proper key types.
 */
export function objectKeys<T extends Record<string, unknown>>(
  obj: T
): Array<keyof T & string> {
  return Object.keys(obj) as Array<keyof T & string>;
}

/**
 * Type-safe Object.values with proper value types.
 */
export function objectValues<T extends Record<string, unknown>>(
  obj: T
): Array<T[keyof T]> {
  return Object.values(obj) as Array<T[keyof T]>;
}

/**
 * Memoize a function with a simple cache.
 * Uses a Map for O(1) lookups. Cache size is unbounded.
 */
export function memoize<TArgs extends unknown[], TResult>(
  fn: (...args: TArgs) => TResult
): (...args: TArgs) => TResult {
  const cache = new Map<string, TResult>();

  return (...args: TArgs): TResult => {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      return cache.get(key)!;
    }
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

/**
 * Debounce a function - only executes after delay ms of no calls.
 */
export function debounce<TArgs extends unknown[]>(
  fn: (...args: TArgs) => void,
  delay: number
): (...args: TArgs) => void {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return (...args: TArgs): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      fn(...args);
      timeoutId = null;
    }, delay);
  };
}

/**
 * Throttle a function - executes at most once per delay ms.
 */
export function throttle<TArgs extends unknown[]>(
  fn: (...args: TArgs) => void,
  delay: number
): (...args: TArgs) => void {
  let lastCall = 0;

  return (...args: TArgs): void => {
    const now = Date.now();
    if (now - lastCall >= delay) {
      lastCall = now;
      fn(...args);
    }
  };
}

/**
 * Deep freeze an object recursively. Returns the same object reference.
 * FIX-003: Optimized to avoid unnecessary iterations.
 */
export function deepFreeze<T extends Record<string, unknown>>(obj: T): Readonly<T> {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  Object.freeze(obj);

  const keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    const value = obj[keys[i]];
    if (value !== null && typeof value === 'object' && !Object.isFrozen(value)) {
      deepFreeze(value as Record<string, unknown>);
    }
  }

  return obj;
}

/**
 * Shallow equality check for objects. Useful for React memo comparisons.
 * FIX-004: Optimized for V8 inline caching.
 */
export function shallowEqual<T extends Record<string, unknown>>(
  objA: T,
  objB: T
): boolean {
  if (objA === objB) {
    return true;
  }

  if (objA === null || objB === null) {
    return false;
  }

  const keysA = Object.keys(objA);
  const keysB = Object.keys(objB);

  if (keysA.length !== keysB.length) {
    return false;
  }

  for (let i = 0; i < keysA.length; i++) {
    const key = keysA[i];
    if (objA[key] !== objB[key]) {
      return false;
    }
  }

  return true;
}
