// Schema - Runtime type validation (TypeBox-inspired API)

/**
 * Schema definition types
 */
type SchemaType =
  | 'string'
  | 'number'
  | 'boolean'
  | 'string?'
  | 'number?'
  | 'boolean?';

type SchemaDefinition = Record<string, SchemaType>;

/**
 * Infer TypeScript type from schema definition
 */
type InferSchemaType<T extends SchemaType> = T extends 'string'
  ? string
  : T extends 'number'
    ? number
    : T extends 'boolean'
      ? boolean
      : T extends 'string?'
        ? string | undefined
        : T extends 'number?'
          ? number | undefined
          : T extends 'boolean?'
            ? boolean | undefined
            : never;

export type InferType<T extends SchemaDefinition> = {
  [K in keyof T]: InferSchemaType<T[K]>;
};

export interface ValidationResult<T> {
  success: boolean;
  data?: T;
  errors?: string[];
}

interface Model<T extends SchemaDefinition> {
  schema: T;
  validate: (data: unknown) => ValidationResult<InferType<T>>;
}

/**
 * Create a runtime-validated model from a schema definition.
 * FIX-009: Stable object shape for V8 optimization.
 */
export function createModel<T extends SchemaDefinition>(schema: T): Model<T> {
  // Pre-compute keys for validation performance
  const schemaKeys = Object.keys(schema);
  const schemaEntries = schemaKeys.map((key) => [key, schema[key]] as const);

  const validateFn = (data: unknown): ValidationResult<InferType<T>> => {
    // FIX-001: Proper null/undefined handling
    if (data === null || data === undefined || typeof data !== 'object') {
      return {
        success: false,
        data: undefined,
        errors: ['Data must be a non-null object'],
      };
    }

    const errors: string[] = [];
    const record = data as Record<string, unknown>;

    // FIX-005: Use for loop instead of forEach for performance
    for (let i = 0; i < schemaEntries.length; i++) {
      const [key, type] = schemaEntries[i];
      const value = record[key];
      const isOptional = type.endsWith('?');
      const baseType = isOptional ? type.slice(0, -1) : type;

      if (value === undefined) {
        if (!isOptional) {
          errors.push(`Missing required field: ${key}`);
        }
        continue;
      }

      if (typeof value !== baseType) {
        errors.push(`Field "${key}" expected ${baseType}, got ${typeof value}`);
      }
    }

    if (errors.length > 0) {
      return {
        success: false,
        data: undefined,
        errors,
      };
    }

    return {
      success: true,
      data: data as InferType<T>,
      errors: undefined,
    };
  };

  // FIX-009: Return stable object shape
  return {
    schema,
    validate: validateFn,
  };
}

/**
 * Standalone validate function for one-off validation.
 */
export function validate<T extends SchemaDefinition>(
  schema: T,
  data: unknown
): ValidationResult<InferType<T>> {
  const model = createModel(schema);
  return model.validate(data);
}
