// State Machine - Redux-like state management with Immer

import { produce, type Draft } from 'immer';

/**
 * Slice configuration
 */
export interface SliceConfig<TState> {
  id: string;
  initial: TState;
  cache?: 'session' | 'local' | 'none';
  reducers: Record<string, (draft: Draft<TState>, payload?: unknown) => void>;
}

export interface Slice<TState> {
  id: string;
  initial: TState;
  cache: 'session' | 'local' | 'none';
  reducers: Record<string, (draft: Draft<TState>, payload?: unknown) => void>;
}

/**
 * Machine configuration
 * FIX-006: Added trackMetadata option for high-frequency machines.
 */
export interface MachineConfig<
  TSlices extends Record<string, Slice<unknown>>,
  TContext,
> {
  id: string;
  trackMetadata?: boolean; // Default: true. Set to false for 60fps performance.
  slices: TSlices;
  context: TContext;
}

type SliceState<T> = T extends Slice<infer S> ? S : never;

type MachineState<TSlices extends Record<string, Slice<unknown>>> = {
  [K in keyof TSlices]: SliceState<TSlices[K]>;
};

type MachineActions<TSlices extends Record<string, Slice<unknown>>> = {
  [K in keyof TSlices]: {
    [A in keyof TSlices[K]['reducers']]: TSlices[K]['reducers'][A] extends (
      draft: Draft<SliceState<TSlices[K]>>,
      payload: infer P
    ) => void
      ? P extends undefined
        ? () => void
        : (payload: P) => void
      : never;
  };
};

export interface Machine<
  TSlices extends Record<string, Slice<unknown>>,
  TContext,
> {
  id: string;
  trackMetadata: boolean;
  context: TContext;
  getState: () => MachineState<TSlices>;
  dispatch: (sliceId: keyof TSlices, action: string, payload?: unknown) => void;
  subscribe: (listener: () => void) => () => void;
  actions: MachineActions<TSlices>;
}

// Global machine registry
const machineRegistry = new Map<string, Machine<Record<string, Slice<unknown>>, unknown>>();

/**
 * Create a slice with reducers.
 * FIX-010: Explicit return type for public function.
 */
export function createSlice<TState>(config: SliceConfig<TState>): Slice<TState> {
  return {
    id: config.id,
    initial: config.initial,
    cache: config.cache ?? 'none',
    reducers: config.reducers,
  };
}

/**
 * Create a state machine from slices.
 * FIX-011: Improved type inference for slices.
 */
export function createMachine<
  TSlices extends Record<string, Slice<unknown>>,
  TContext,
>(config: MachineConfig<TSlices, TContext>): Machine<TSlices, TContext> {
  const { id, slices, context, trackMetadata = true } = config;

  // Initialize state from slices - FIX-005: Use for loop
  const sliceKeys = Object.keys(slices);
  const initialState: Record<string, unknown> = {};

  for (let i = 0; i < sliceKeys.length; i++) {
    const key = sliceKeys[i];
    initialState[key] = slices[key].initial;
  }

  let state = initialState as MachineState<TSlices>;
  const listeners = new Set<() => void>();

  const dispatch = (sliceId: keyof TSlices, action: string, payload?: unknown): void => {
    const slice = slices[sliceId as string];
    if (!slice) {
      if (process.env.NODE_ENV !== 'production') {
        console.error(`Slice "${String(sliceId)}" not found`);
      }
      return;
    }

    const reducer = slice.reducers[action];
    if (!reducer) {
      if (process.env.NODE_ENV !== 'production') {
        console.error(`Action "${action}" not found in slice "${String(sliceId)}"`);
      }
      return;
    }

    const newSliceState = produce(state[sliceId], (draft) => {
      reducer(draft as Draft<unknown>, payload);
    });

    // Only update if state actually changed
    if (newSliceState !== state[sliceId]) {
      state = { ...state, [sliceId]: newSliceState };

      // Notify listeners - FIX-005: Use for loop with array
      const listenerArray = Array.from(listeners);
      for (let i = 0; i < listenerArray.length; i++) {
        listenerArray[i]();
      }
    }
  };

  const subscribe = (listener: () => void): (() => void) => {
    listeners.add(listener);
    return () => {
      listeners.delete(listener);
    };
  };

  // Build actions object - FIX-012: Pre-bound action creators
  const actions = {} as MachineActions<TSlices>;

  for (let i = 0; i < sliceKeys.length; i++) {
    const sliceKey = sliceKeys[i] as keyof TSlices;
    const slice = slices[sliceKey as string];
    const reducerKeys = Object.keys(slice.reducers);
    const sliceActions: Record<string, (payload?: unknown) => void> = {};

    for (let j = 0; j < reducerKeys.length; j++) {
      const reducerKey = reducerKeys[j];
      // Pre-bind dispatch to avoid closure allocation in hot path
      sliceActions[reducerKey] = (payload?: unknown) => {
        dispatch(sliceKey, reducerKey, payload);
      };
    }

    (actions as Record<string, unknown>)[sliceKey as string] = sliceActions;
  }

  const machine: Machine<TSlices, TContext> = {
    id,
    trackMetadata,
    context,
    getState: () => state,
    dispatch,
    subscribe,
    actions,
  };

  // Register machine globally
  machineRegistry.set(id, machine as Machine<Record<string, Slice<unknown>>, unknown>);

  return machine;
}

/**
 * React hook to use a machine's state and actions.
 * FIX-007: Changed return type from tuple to object.
 */
export function useMachine<TSlices extends Record<string, Slice<unknown>>, TContext>(
  machineId: string
): { state: MachineState<TSlices>; actions: MachineActions<TSlices> } {
  const machine = machineRegistry.get(machineId) as Machine<TSlices, TContext> | undefined;

  if (!machine) {
    throw new Error(`Machine "${machineId}" not found. Did you forget to create it?`);
  }

  // Note: In a real implementation, this would use React.useSyncExternalStore
  // This is a simplified version for the library structure
  return {
    state: machine.getState(),
    actions: machine.actions,
  };
}

/**
 * React hook to select a slice of state with memoization.
 */
export function useSelector<TSlices extends Record<string, Slice<unknown>>, TSelected>(
  machineId: string,
  selector: (state: MachineState<TSlices>) => TSelected
): TSelected {
  const machine = machineRegistry.get(machineId) as Machine<TSlices, unknown> | undefined;

  if (!machine) {
    throw new Error(`Machine "${machineId}" not found. Did you forget to create it?`);
  }

  // Note: In a real implementation, this would use React.useSyncExternalStore
  // with a memoized selector
  return selector(machine.getState());
}
