import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import {
  devLog,
  devAssert,
  objectEntries,
  objectKeys,
  objectValues,
  memoize,
  debounce,
  throttle,
  deepFreeze,
  shallowEqual,
} from '../index';

describe('helpers', () => {
  describe('devLog', () => {
    const originalEnv = process.env.NODE_ENV;

    afterEach(() => {
      process.env.NODE_ENV = originalEnv;
    });

    it('logs error in development', () => {
      process.env.NODE_ENV = 'development';
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      const error = new Error('test error');
      devLog(error);

      expect(consoleSpy).toHaveBeenCalledWith('[devLog]', 'test error', error);
      consoleSpy.mockRestore();
    });

    it('is silent in production', () => {
      process.env.NODE_ENV = 'production';
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      devLog(new Error('test error'));

      expect(consoleSpy).not.toHaveBeenCalled();
      consoleSpy.mockRestore();
    });
  });

  describe('devAssert', () => {
    const originalEnv = process.env.NODE_ENV;

    afterEach(() => {
      process.env.NODE_ENV = originalEnv;
    });

    it('throws in development', () => {
      process.env.NODE_ENV = 'development';
      expect(() => devAssert(new Error('test'))).toThrow('test');
    });

    it('is silent in production', () => {
      process.env.NODE_ENV = 'production';
      expect(() => devAssert(new Error('test'))).not.toThrow();
    });
  });

  describe('objectEntries', () => {
    it('returns typed entries', () => {
      const obj = { a: 1, b: 2, c: 3 };
      const entries = objectEntries(obj);

      expect(entries).toEqual([
        ['a', 1],
        ['b', 2],
        ['c', 3],
      ]);
    });
  });

  describe('objectKeys', () => {
    it('returns typed keys', () => {
      const obj = { a: 1, b: 2 };
      const keys = objectKeys(obj);

      expect(keys).toEqual(['a', 'b']);
    });
  });

  describe('objectValues', () => {
    it('returns typed values', () => {
      const obj = { a: 1, b: 2 };
      const values = objectValues(obj);

      expect(values).toEqual([1, 2]);
    });
  });

  describe('memoize', () => {
    it('caches function results', () => {
      let callCount = 0;
      const fn = (a: number, b: number) => {
        callCount++;
        return a + b;
      };
      const memoized = memoize(fn);

      expect(memoized(1, 2)).toBe(3);
      expect(memoized(1, 2)).toBe(3);
      expect(callCount).toBe(1);

      expect(memoized(2, 3)).toBe(5);
      expect(callCount).toBe(2);
    });
  });

  describe('debounce', () => {
    beforeEach(() => {
      vi.useFakeTimers();
    });

    afterEach(() => {
      vi.useRealTimers();
    });

    it('debounces function calls', () => {
      let callCount = 0;
      const fn = debounce(() => {
        callCount++;
      }, 100);

      fn();
      fn();
      fn();

      expect(callCount).toBe(0);

      vi.advanceTimersByTime(100);

      expect(callCount).toBe(1);
    });
  });

  describe('throttle', () => {
    beforeEach(() => {
      vi.useFakeTimers();
    });

    afterEach(() => {
      vi.useRealTimers();
    });

    it('throttles function calls', () => {
      let callCount = 0;
      const fn = throttle(() => {
        callCount++;
      }, 100);

      fn(); // Called immediately
      fn(); // Ignored
      fn(); // Ignored

      expect(callCount).toBe(1);

      vi.advanceTimersByTime(100);

      fn(); // Called after delay
      expect(callCount).toBe(2);
    });
  });

  describe('deepFreeze', () => {
    it('freezes object recursively', () => {
      const obj = {
        a: 1,
        nested: {
          b: 2,
          deep: {
            c: 3,
          },
        },
      };

      const frozen = deepFreeze(obj);

      expect(Object.isFrozen(frozen)).toBe(true);
      expect(Object.isFrozen(frozen.nested)).toBe(true);
      expect(Object.isFrozen(frozen.nested.deep)).toBe(true);
    });
  });

  describe('shallowEqual', () => {
    it('returns true for identical objects', () => {
      const obj = { a: 1 };
      expect(shallowEqual(obj, obj)).toBe(true);
    });

    it('returns true for equal objects', () => {
      expect(shallowEqual({ a: 1, b: 2 }, { a: 1, b: 2 })).toBe(true);
    });

    it('returns false for different objects', () => {
      expect(shallowEqual({ a: 1 }, { a: 2 })).toBe(false);
    });

    it('returns false for different key counts', () => {
      expect(shallowEqual({ a: 1 }, { a: 1, b: 2 })).toBe(false);
    });
  });
});
