import { describe, it, expect } from 'vitest';
import { createModel, validate, type InferType } from '../index';

describe('schema', () => {
  describe('createModel', () => {
    it('creates a model with validate function', () => {
      const UserSchema = createModel({
        id: 'number',
        name: 'string',
      });

      expect(UserSchema.schema).toEqual({
        id: 'number',
        name: 'string',
      });
      expect(typeof UserSchema.validate).toBe('function');
    });

    it('validates correct data', () => {
      const UserSchema = createModel({
        id: 'number',
        name: 'string',
        active: 'boolean',
      });

      const result = UserSchema.validate({
        id: 1,
        name: 'John',
        active: true,
      });

      expect(result.success).toBe(true);
      expect(result.data).toEqual({
        id: 1,
        name: 'John',
        active: true,
      });
    });

    it('rejects null data', () => {
      const UserSchema = createModel({
        id: 'number',
      });

      const result = UserSchema.validate(null);

      expect(result.success).toBe(false);
      expect(result.errors).toContain('Data must be a non-null object');
    });

    it('rejects undefined data', () => {
      const UserSchema = createModel({
        id: 'number',
      });

      const result = UserSchema.validate(undefined);

      expect(result.success).toBe(false);
      expect(result.errors).toContain('Data must be a non-null object');
    });

    it('reports missing required fields', () => {
      const UserSchema = createModel({
        id: 'number',
        name: 'string',
      });

      const result = UserSchema.validate({ id: 1 });

      expect(result.success).toBe(false);
      expect(result.errors).toContain('Missing required field: name');
    });

    it('reports type mismatches', () => {
      const UserSchema = createModel({
        id: 'number',
      });

